  .slide-5 { background: var(--bg-dark); }
  .slide-5 .slide-label { color: var(--accent-purple); }
  .slide-5 .story-content {
    display: flex;
    flex-direction: column;
    gap: 32px;
    margin-top: 16px;
  }
  .slide-5 .story-block {
    background: var(--bg-card);
    border-radius: 16px;
    padding: 36px;
    border-left: 4px solid;
  }
  .slide-5 .story-block h3 {
    font-size: 24px;
    font-weight: 700;
    color: var(--text-primary);
    margin-bottom: 12px;
  }
  .slide-5 .story-block p {
    font-size: 22px;
    color: var(--text-secondary);
    line-height: 1.55;
  }
  .slide-5 .story-block .stat-inline {
    font-size: 42px;
    font-weight: 800;
    margin: 16px 0 8px;
  }

  /* ════════════════════════════════════════════════════ */
  /* SLIDE 6 — NUMBERS                                  */
  /* ════════════════════════════════════════════════════ */
  .slide-6 { background: var(--bg-dark); }
  .slide-6 .slide-label { color: var(--accent-cyan); }

  .slide-6 .stat-grid {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 28px;
    flex: 1;
    align-content: center;
  }
  .slide-6 .stat-box {
    background: var(--bg-card);
    border-radius: 16px;
    padding: 48px 28px;
    text-align: center;
  }

  /* ════════════════════════════════════════════════════ */
  /* SLIDE 7 — WHAT EXISTS TODAY (clean)                */
  /* ════════════════════════════════════════════════════ */
  .slide-7 { background: var(--bg-dark); }
  .slide-7 .slide-label { color: var(--accent-green); }
